const body = $input.first().json.body || $input.first().json;
const db06_id = (body.db06_id || body.id || '').toString().replace(/-/g, '');
if (!db06_id) throw new Error('missing db06_id');
return [{ json: { db06_id } }];

const p = $input.first().json;
const TARGET_RELS = ["對應提案", "對應管考", "對應項目", "對應協作", "對應內容", "對應庫存", "對應對象", "對應標籤", "對應地點", "對應提供對象"];
let target_id = '', target_rel = '';
for (const rel of TARGET_RELS) {
  const arr = p.properties[rel]?.relation || [];
  if (arr.length) { target_id = (arr[0].id||'').replace(/-/g,''); target_rel = rel; break; }
}
return [{ json: {
  db06_id: p.id.replace(/-/g, ''),
  ai_mode: p.properties['ai模式']?.select?.name || '',
  execute_idea_db06: p.properties['執行構想']?.rich_text?.map(t=>t.plain_text).join('') || '',
  mingxi_content: p.properties['明細內容']?.rich_text?.map(t=>t.plain_text).join('') || '',
  db05_id: target_id,
  target_rel: target_rel,
  mingxi_name: p.properties['明細名稱']?.title?.map(t=>t.plain_text).join('') || '',
  sort_num: p.properties['排序']?.number
}}];

const baton = $('Parse DB06').first().json;
const target = $input.first().json;
const tp = target.properties || {};
const NHEAD={'Authorization':'Bearer '+$env.NOTION_INTEGRATION_TOKEN,'Notion-Version':'2022-06-28','Content-Type':'application/json'};
const norm=id=>(id||'').replace(/-/g,'');
const withTO=(p,ms)=>Promise.race([p,new Promise((_,r)=>setTimeout(()=>r(new Error('to')),ms))]);
const sleep=ms=>new Promise(r=>setTimeout(r,ms));
const getPage=async id=>{try{const r=await withTO(this.helpers.httpRequest({method:'GET',url:'https://api.notion.com/v1/pages/'+id,headers:NHEAD}),10000);return (typeof r==='string')?JSON.parse(r):r;}catch(e){return null;}};
const titleProp=Object.values(tp).find(v=>v&&v.type==='title');
const target_name=(titleProp?.title||[]).map(t=>t.plain_text).join('')||'(未命名)';
const rt=k=>(tp[k]?.rich_text||[]).map(t=>t.plain_text).join('');
const cur_idea=rt('執行構想');
const summary=rt('簡介摘要');
const analysis=rt('分析備註');
const copyType=tp['文案選項']?.select?.name||'';
const XF=['提案引用','管考引用','項目引用','協作引用','內容引用','明細引用','庫存引用','對象引用','日期引用'];
let refIds=[];for(const f of XF){for(const r of ((tp[f]&&tp[f].relation)||[]))refIds.push(norm(r.id));}
refIds=[...new Set(refIds)].slice(0,30);
let refs=[];
for(let i=0;i<refIds.length;i+=4){const part=await Promise.all(refIds.slice(i,i+4).map(getPage));for(const pg of part){if(!pg)continue;const pt=Object.values(pg.properties||{}).find(v=>v&&v.type==='title');const nm=(pt?.title||[]).map(t=>t.plain_text).join('');const mc=((pg.properties||{})['明細內容']?.rich_text||[]).map(t=>t.plain_text).join('');const sm=((pg.properties||{})['簡介摘要']?.rich_text||[]).map(t=>t.plain_text).join('');if(nm||mc||sm)refs.push('・'+nm+(mc||sm?('：'+(mc||sm).slice(0,200)):''));}if(i+4<refIds.length)await sleep(320);}
const system="你是 makesense（現思文化創藝有限公司，宜蘭在地文化事業）嗨嗨家族的嗨嗨文案。職責：依 target 的執行構想（內含企劃寫好的章節架構）寫出 target 的頁面正文。\\n== 鐵律 ==\\n1. 執行構想是最高指示：企劃已把內容拆成數個 ## 章節、每章標了目標字數與素材方向。逐章寫，章節數與標題對齊執行構想，不增不減。\\n2. 每章字數對齊執行構想標的目標字數。\\n3. 具體可查證：用具名事件/日期/人物/數字/地點。嚴禁堆疊沒有實據的空泛形容詞（氛圍詞）。\\n4. 素材未齊的部分（執行構想標「待補」者）：就現有素材能寫多少寫多少，不硬編數字、不杜撰，可寫「此部分待補」帶過，不要假裝有資料。\\n5. 一律繁體中文。正文用 markdown：章節標題用 ## 開頭，內文分段。\\n== 輸出 只回合法 JSON ==\\n{\"execution_summary\":\"寫了什麼、總字數、依幾章\",\"page_content\":\"完整正文 markdown，## 章節標題 + 內文段落\",\"needs_human_intervention\":false}";
const user='target 名稱：'+target_name+'\n文案類型：'+(copyType||'(未指定)')+'\n\n【執行構想 — 企劃寫好的章節架構，逐章照寫】\n'+(cur_idea||'(空)')+'\n\n【簡介摘要】\n'+(summary||'(空)')+'\n\n【分析備註 — 嗨嗨分析鑑定的重點與數據】\n'+(analysis||'(空)')+'\n\n【參考資料 '+refs.length+' 筆（X引用的 DB06 資料參考）】\n'+(refs.join('\n')||'(無)')+'\n\n依執行構想的章節架構逐章寫正文，回 JSON。';
return [{json:{system,user,target_name,target_id:baton.db05_id,db06_id:baton.db06_id,ai_mode:baton.ai_mode||'文案',sort_num:baton.sort_num,ref_count:refs.length}}];

const resp = $input.first().json;
const ctx = $('Build Claude prompt').first().json;
const text = resp.content?.[0]?.text || '';
const usage = resp.usage || {};
let p; try { const m=text.match(/\{[\s\S]*\}/); p=m?JSON.parse(m[0]):{}; } catch(e){ p={}; }
const md = (p.page_content||'').toString();
const lines = md.split('\n');
const blocks = []; let para = [];
const flush = () => { if(para.length){ const txt=para.join('\n').trim(); if(txt){ for(let i=0;i<txt.length;i+=2000) blocks.push({object:'block',type:'paragraph',paragraph:{rich_text:[{text:{content:txt.slice(i,i+2000)}}]}}); } para=[]; } };
for (const ln of lines) {
  const h2 = ln.match(/^##\s+(.+)/); const h1 = ln.match(/^#\s+(.+)/);
  if (h2) { flush(); blocks.push({object:'block',type:'heading_2',heading_2:{rich_text:[{text:{content:h2[1].slice(0,2000)}}]}}); }
  else if (h1) { flush(); blocks.push({object:'block',type:'heading_1',heading_1:{rich_text:[{text:{content:h1[1].slice(0,2000)}}]}}); }
  else if (ln.trim()==='') { flush(); }
  else para.push(ln);
}
flush();
const children = blocks.slice(0,100);
const wordCount = md.replace(/\s/g,'').length;
const it=parseInt(usage.input_tokens||0), ot=parseInt(usage.output_tokens||0);
const cost=((it*3+ot*15)/1000000*32).toFixed(2);
const usage_line='進='+it+' 出='+ot+' 成本NT'+cost;
const d=new Date(); const tw=new Date(d.getTime()+8*3600*1000);
const ts=tw.getUTCFullYear()+'-'+String(tw.getUTCMonth()+1).padStart(2,'0')+'-'+String(tw.getUTCDate()).padStart(2,'0')+' '+String(tw.getUTCHours()).padStart(2,'0')+':'+String(tw.getUTCMinutes()).padStart(2,'0');
const exec_summary=(p.execution_summary||'文案完成').toString();
const exec_note=('── '+ts+' 文案 ──\n工作對象：'+ctx.target_name+'\n做了什麼：寫 target 頁面正文 約 '+wordCount+' 字、'+blocks.filter(b=>b.type!=='paragraph').length+' 章節\n參考資料：'+ctx.ref_count+' 筆\n'+exec_summary).slice(0,1990);
const sanitize=s=>(s||'').toString().replace(/[\/\\:<>#@\[\]\{\}\|\^\`\*_~"']/g,' ').replace(/\s+/g,' ').trim().slice(0,500);
return [{ json: { db06_id:ctx.db06_id, db05_id:ctx.target_id, target_id:ctx.target_id, ai_mode:ctx.ai_mode, sort_num:ctx.sort_num,
  children, has_content: children.length>0, word_count:wordCount, exec_note, usage_line,
  safe_summary:sanitize(exec_note), preview_text:'文案寫入 '+wordCount+' 字 / '+children.length+' blocks', validator_warning:'' } }];

const row = $input.first().json || {};
const pc = $('Parse Claude').first().json;
const auto_mode = row.auto_mode === true;
const reply_to = parseInt(row.last_msg_id || 0) || 0;
const base = '關卡B 成果確認
第 ' + (pc.sort_num != null ? pc.sort_num : '?') + ' 棒 (' + pc.ai_mode + ') 已完成。
DB06 頁面 ' + pc.db06_id + '

執行備註:
' + pc.safe_summary + '

' + pc.preview_text + (pc.validator_warning || '') + '
tokens ' + pc.usage_line;
const manual_msg = base + '

按 OK 進下一棒,按 OK ALL 之後全自動。要 redo 重跑請打字 reply。
gateB db06=' + pc.db06_id;
const auto_msg = base + '

[全自動模式] 自動進下一棒,免按。';
return [{ json: { auto_mode, reply_to, flow_id: pc.db05_id, db05_id: pc.db05_id, db06_id: pc.db06_id, sort_num: pc.sort_num, ai_mode: pc.ai_mode, manual_msg, auto_msg, cb_ok: 'B1:' + pc.db06_id, cb_all: 'BA:' + pc.db06_id } }];

