const results = $input.first().json.results || [];
const g = $('Build gateB').first().json;
const pending = results.filter(p => (p.properties['ai狀態']?.status?.name||'') !== '完成');
const total = results.length;
if (pending.length === 0) {
  return [{ json: { has_next: false, tg_message: '全套完成 共 ' + total + ' 棒已全部通過 (全自動模式)。' } }];
}
const p = pending[0];
const db06_id = p.id.replace(/-/g, '');
const ai_mode = p.properties['ai模式']?.select?.name || '';
let runner_url;
const _b = 'https://makesense.zeabur.app/webhook/';
if (ai_mode.includes('聯想')) runner_url = _b + 'db06-lianxiang-traversal';
else if (ai_mode.includes('搜查')) runner_url = _b + 'db06-search';
else if (ai_mode.includes('分析')) runner_url = _b + 'db06-analyze';
else if (ai_mode.includes('文案')) runner_url = _b + 'db06-copy';
else if (ai_mode.includes('檢核')) runner_url = _b + 'db06-check';
else runner_url = _b + 'db06-plan';
return [{ json: { has_next: true, db06_id, runner_url, tg_message: '' } }];
